// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAX_N 300
#define MAX_R 300
#define MAX_G 300
#define MAX_B 300

int dp[MAX_N + 1][MAX_R + 1][MAX_G + 1][MAX_B + 1];
int N, R, G, B;
int edges[MAX_N][2];

int dfs(int node, int red, int green, int blue) {
    if (dp[node][red][green][blue] != -1) return dp[node][red][green][blue];
    int result = 0;
    if (red <= R) result = (result + dfs(node, red + 1, green, blue)) % MOD;
    if (green <= G) result = (result + dfs(node, red, green + 1, blue)) % MOD;
    if (blue <= B) result = (result + dfs(node, red, green, blue + 1)) % MOD;
    return dp[node][red][green][blue] = result;
}

int main() {
    scanf("%d %d %d %d", &N, &R, &G, &B);
    for (int i = 0; i < N - 1; i++) {
        scanf("%d %d", &edges[i][0], &edges[i][1]);
    }
    for (int i = 0; i <= N; i++) {
        for (int j = 0; j <= R; j++) {
            for (int k = 0; k <= G; k++) {
                for (int l = 0; l <= B; l++) {
                    dp[i][j][k][l] = -1;
                }
            }
        }
    }
    printf("%d\n", dfs(0, 0, 0, 0));
    return 0;
}

